mapper.select:
select 
from template_variable_description
where template_id = #{templateId}
  and file_id = #{fileId}
  and variable_name = #{variableName}
limit 1

select 
from template_variable_description
where template_id = #{templateId}
  and file_id = #{fileId}
  and deleted = 0
order by id asc

mapper.update:
update template_variable_description
set project_id = #{projectId},
    description = #{description},
    updated_by = #{updatedBy},
    deleted = 0,
    updated_at = current_timestamp
where id = #{id}
  and template_id = #{templateId}
  and file_id = #{fileId}
  and variable_name = #{variableName}
